using System;
using System.Diagnostics;
using TextAnalysis;

// Setup
var smallAnalyzer = new TextAnalyzer("The quick brown fox jumps over the lazy dog");

var rng = new Random(42);
var words = new string[1000];
for (int i = 0; i < words.Length; i++)
{
    int len = rng.Next(1, 15);
    var chars = new char[len];
    for (int j = 0; j < len; j++)
        chars[j] = (char)('a' + rng.Next(0, 26));
    words[i] = new string(chars);
}
var largeAnalyzer = new TextAnalyzer(string.Join(' ', words));

Console.WriteLine($"Runtime: {System.Runtime.InteropServices.RuntimeInformation.FrameworkDescription}");
Console.WriteLine($"{"Method",-35} {"Mean",12} {"Allocated",12}");
Console.WriteLine(new string('-', 61));

RunBenchmark("AverageWordLength_Small", () => smallAnalyzer.AverageWordLength());
RunBenchmark("AverageWordLength_Large", () => largeAnalyzer.AverageWordLength());
RunBenchmark("WordLengthHistogram_Small", () => smallAnalyzer.WordLengthHistogram());
RunBenchmark("WordLengthHistogram_Large", () => largeAnalyzer.WordLengthHistogram());
RunBenchmark("UniqueWordCount_Small", () => smallAnalyzer.UniqueWordCount());
RunBenchmark("UniqueWordCount_Large", () => largeAnalyzer.UniqueWordCount());

static void RunBenchmark(string name, Func<object?> action)
{
    // Warmup
    for (int i = 0; i < 1000; i++) action();

    // Measure allocation
    GC.Collect(2, GCCollectionMode.Forced, true, true);
    GC.WaitForPendingFinalizers();
    long memBefore = GC.GetTotalAllocatedBytes(true);
    const int allocRuns = 10000;
    for (int i = 0; i < allocRuns; i++) action();
    long memAfter = GC.GetTotalAllocatedBytes(true);
    long bytesPerOp = (memAfter - memBefore) / allocRuns;

    // Measure time - run multiple rounds to pick the best median
    const int outerRounds = 5;
    double[] medians = new double[outerRounds];

    for (int round = 0; round < outerRounds; round++)
    {
        const int innerIterations = 7;
        double[] times = new double[innerIterations];

        for (int iter = 0; iter < innerIterations; iter++)
        {
            // Determine how many ops to fit ~50ms
            int ops = 1000;
            var probe = Stopwatch.StartNew();
            for (int i = 0; i < ops; i++) action();
            probe.Stop();
            if (probe.Elapsed.TotalMilliseconds < 10)
            {
                ops = (int)(ops * 50.0 / Math.Max(probe.Elapsed.TotalMilliseconds, 0.01));
                ops = Math.Max(ops, 1000);
            }

            GC.Collect(2, GCCollectionMode.Forced, true, true);
            GC.WaitForPendingFinalizers();

            var sw = Stopwatch.StartNew();
            for (int i = 0; i < ops; i++) action();
            sw.Stop();
            times[iter] = sw.Elapsed.TotalNanoseconds / ops;
        }

        Array.Sort(times);
        medians[round] = times[innerIterations / 2];
    }

    Array.Sort(medians);
    double medianNs = medians[outerRounds / 2];

    string timeStr = medianNs >= 1000 ? $"{medianNs / 1000:F3} μs" : $"{medianNs:F3} ns";
    string allocStr = bytesPerOp > 0 ? $"{bytesPerOp} B" : "-";
    Console.WriteLine($"{name,-35} {timeStr,12} {allocStr,12}");
}

