            for (int i = 0; i < ops; i++) action();
            probe.Stop();
            if (probe.Elapsed.TotalMilliseconds < 10)
            {
                ops = (int)(ops * 50.0 / Math.Max(probe.Elapsed.TotalMilliseconds, 0.01));
                ops = Math.Max(ops, 1000);
            }

            GC.Collect(2, GCCollectionMode.Forced, true, true);
            GC.WaitForPendingFinalizers();

            var sw = Stopwatch.StartNew();
            for (int i = 0; i < ops; i++) action();
            sw.Stop();
            times[iter] = sw.Elapsed.TotalNanoseconds / ops;
        }

        Array.Sort(times);
        medians[round] = times[innerIterations / 2];
    }

    Array.Sort(medians);
    double medianNs = medians[outerRounds / 2];

    string timeStr = medianNs >= 1000 ? $"{medianNs / 1000:F3} μs" : $"{medianNs:F3} ns";
    string allocStr = bytesPerOp > 0 ? $"{bytesPerOp} B" : "-";
    Console.WriteLine($"{name,-35} {timeStr,12} {allocStr,12}");
}

